+const hoisted = vi.hoisted(() => ({
+  sendDiscordComponentMessageMock: vi.fn(),
+  sendMessageDiscordMock: vi.fn(),
+  sendPollDiscordMock: vi.fn(),
+  sendWebhookMessageDiscordMock: vi.fn(),
+  getThreadBindingManagerMock: vi.fn(),
